<template><div class="space-y-4"><h2 class="text-xl font-bold" style="color:#00f0ff">💬 在线聊天</h2><div class="grid grid-cols-1 md:grid-cols-3 gap-4" style="height:600px"><div class="cyber-card rounded-xl overflow-hidden flex flex-col"><div class="p-3 border-b" style="border-color:#00f0ff20"><h3 class="text-sm font-bold" style="color:#ff2d95">会话列表 ({{chats.length}})</h3></div><div class="flex-1 overflow-y-auto"><div v-for="c in chats" :key="c.id" @click="active=c.id" class="p-3 cursor-pointer border-b" :style="active===c.id?'background:#00f0ff10':''" style="border-color:#00f0ff10"><div class="flex justify-between"><span class="text-sm" style="color:#e0e0ff">{{c.name}}</span><span class="text-xs" style="color:#a0a0cc">{{c.time}}</span></div><div class="text-xs mt-1 truncate" style="color:#a0a0cc">{{c.last}}</div></div></div></div><div class="md:col-span-2 cyber-card rounded-xl flex flex-col"><div class="p-3 border-b flex items-center gap-2" style="border-color:#00f0ff20"><div class="w-2 h-2 rounded-full" style="background:#00ff88"></div><span class="text-sm font-bold" style="color:#e0e0ff">{{activeChat?.name||'选择会话'}}</span></div><div class="flex-1 overflow-y-auto p-4 space-y-3"><div v-for="msg in messages" :key="msg.id" class="flex" :class="msg.me?'justify-end':'justify-start'"><div class="max-w-[70%] px-3 py-2 rounded-xl text-sm" :style="msg.me?'background:#00f0ff20;color:#00f0ff':'background:#0d0d1a;color:#e0e0ff;border:1px solid #00f0ff20'">{{msg.text}}</div></div></div><div class="p-3 border-t flex gap-2" style="border-color:#00f0ff20"><input v-model="input" @keyup.enter="send" placeholder="输入消息..." class="flex-1 px-3 py-2 rounded-lg text-sm" style="background:#0d0d1a;border:1px solid #00f0ff30;color:#e0e0ff;outline:none"/><button @click="send" class="px-4 py-2 rounded-lg text-sm" style="background:linear-gradient(135deg,#00f0ff,#b700ff);color:#fff">发送</button></div></div></div></div></template>
<script setup lang="ts">
import {ref,computed} from 'vue'
const active=ref(1),input=ref('')
const chats=ref([{id:1,name:'用户A',time:'刚刚',last:'你好，我想问一下...'},{id:2,name:'用户B',time:'5分钟前',last:'充值没有到账'},{id:3,name:'访客_003',time:'12分钟前',last:'怎么使用AI绘画?'}])
const activeChat=computed(()=>chats.value.find(c=>c.id===active.value))
const messages=ref([{id:1,me:false,text:'你好，我想咨询一下平台功能'},{id:2,me:true,text:'您好！欢迎咨询罗圣纪元平台'},{id:3,me:false,text:'AI对话的额度怎么算？'},{id:4,me:true,text:'每日免费100次，VIP不限次数。'}])
function send(){if(!input.value.trim())return;messages.value.push({id:Date.now(),me:true,text:input.value});input.value=''}
</script>